import math

def find_min_diff(packets, m):
    if m <= 0 or not packets or len(packets) < m:
        return math.inf

    packets.sort()

    min_diff = math.inf

    for i in range(len(packets) - m + 1):
        current_diff = packets[i + m - 1] - packets[i]
        min_diff = min(min_diff, current_diff)

    return min_diff
